tool_log.command:
# Check for any web driver or browser session indicators
env | grep -iE 'browser|chrom|webdriver|cdp|selenium|puppeteer|playwright' 2>/dev/null; echo "---";
# Check for running display server
echo "DISPLAY=$DISPLAY"; echo "---";
# Check for common browser state files
ls -la /tmp/.X* 2>/dev/null; ls -la /tmp/chrome* 2>/dev/null; echo "---";
# Check if any browser is installed
which chromium google-chrome chromium-browser firefox 2>/dev/null || echo "no browser binaries found"
